/**
 * 手机号
 * @param str
 * @returns
 */
export const phone = (str: string): string => {
  if (!str) return ''
  const pat = /(\d{3})\d*(\d{4})/
  return str.replace(pat, '$1****$2')
}

/**
 * 邮箱
 * @param str
 * @returns
 */
export const email = (str: string): string => {
  if (!str) return ''
  const pat = /(^\w)[^@]*(@.*$)/
  return str.replace(pat, '$1****$2')
}

/**
 * 银行卡
 * @param str
 * @returns
 */
export const idcard = (str: string): string => {
  if (!str) return ''
  const pat = /(\d{4})\d*(\d{4})/
  return str.replace(pat, '$1***********$2')
}

/**
 * 中文名
 * @param str
 * @returns
 */
export const name = (str: string): string => {
  if (!str) return ''
  let pat = null
  if (str.length === 2) {
    pat = /.*([\u4e00-\u9fa5])/
    return str.replace(pat, '*$1')
  }
  if (str.length > 2) {
    pat = /([\u4e00-\u9fa5]).*([\u4e00-\u9fa5])/
    return str.replace(pat, '$1*$2')
  }
  return str
}
